{
  "formal_minutes": {
    "회의_기본정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "확정_결정": [
      {
        "주제": "공개 릴리스 목표 시점",
        "내용": "스모크 테스트 통과를 전제로 공개 릴리스 목표는 금요일 15:00 KST로 둔다."
      },
      {
        "주제": "packageName mismatch 대응 원칙",
        "내용": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "반려_제안": [
      {
        "제안자": "Hara",
        "주제": "smoke-theme-pack.mjs 처리 방식",
        "내용": "packageName mismatch를 무시하도록 smoke-theme-pack.mjs를 변경하자는 제안은 반려되었다."
      }
    ],
    "내부_스트레치_목표": [
      {
        "제안자": "Seoyeon",
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표로만 남았고 확정 일정은 아니다."
      }
    ],
    "비결정_사항": [
      {
        "내용": "README 설치 절차는 가능하면 목요일까지 검토하는 것이 제안되었으나 담당자는 지정되지 않았다."
      }
    ],
    "리스크": [
      {
        "내용": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "내용": "README 설치 절차가 오래되어 있으면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "오픈_질문": [
      {
        "내용": "최종 릴리스 승인 권한자가 누구인가?"
      },
      {
        "내용": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 점검한다.",
      "due": null,
      "status": "선행 결과 대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시점",
      "status": "담당자 미지정",
      "source_certainty": "제안 수준"
    }
  ],
  "followup_note": {
    "다음_확인사항": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과를 확인한다.",
      "스모크 통과 여부를 기준으로 금요일 15:00 KST 공개 릴리스 목표 유지 가능성을 재확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "금요일 12:00 KST 이후 Doyun의 실패 트리아지 노트 작성 여부를 확인한다.",
      "README 설치 절차 검토 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 결정해야 한다."
    ],
    "발명_금지사항": [
      "고객명이나 외부 파트너를 추가하지 않는다.",
      "예산 정보를 추가하지 않는다.",
      "보안 사고를 추가하지 않는다.",
      "프로덕션 장애를 추가하지 않는다.",
      "법무 승인 요건을 추가하지 않는다.",
      "지정되지 않은 담당자나 마감시한을 임의로 추가하지 않는다."
    ]
  },
  "non_invention_rules": [
    "이 출력은 제공된 공개용 합성 회의 메모에만 근거한다.",
    "확정된 내용, 반려된 제안, 내부 스트레치 목표, 리스크, 오픈 질문을 혼합하지 않는다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, 담당자, 마감 정보는 쓰지 않는다.",
    "상대적 일정 표현은 원문 그대로 유지하고, 추가 날짜 계산은 하지 않는다."
  ]
}
